proof_block:
// The ensures of this proof fn is `BIG_AND ==> det_page_to_thread_with_endpoint_equal(r1, r2)`,
// so the conjuncts of BIG_AND are NOT hypotheses at the top of the body — they form the
// antecedent of an implication. The previous attempt's bare `assert(r1.0 == page_ptr)` etc.
// therefore failed (nothing in `requires` links r1/r2 to page_ptr / owning_container / …).
//
// The fix: gate the entire proof on BIG_AND with an `if (LHS) { … }`. Inside the then-branch
// every ensures-conjunct for r1 and r2 becomes a hypothesis, so each cross-run pointwise
// equality follows by transitivity, and the else-branch closes the implication vacuously.
if r1.0 == page_ptr
    && r1.1@.is_init()
    && r1.1@.addr() == r1.0
    && r1.1@.value().owning_container == owning_container
    && r1.1@.value().owning_proc == owning_proc
    && r1.1@.value().state == ThreadState::SCHEDULED
    && r1.1@.value().proc_rev_ptr == proc_rev_ptr
    && r1.1@.value().scheduler_rev_ptr == Some(scheduler_rev_ptr)
    && (r1.1@.value().blocking_endpoint_ptr is None)
    && (r1.1@.value().endpoint_rev_ptr is None)
    && (r1.1@.value().running_cpu is None)
    && r1.1@.value().endpoint_descriptors@ =~= Seq::new(
        MAX_NUM_ENDPOINT_DESCRIPTORS as nat,
        |i: int| { None },
    ).update(0, Some(endpoint_ptr))
    && (r1.1@.value().ipc_payload is None)
    && (r1.1@.value().error_code is None)
    && r1.1@.value().trap_frame.unwrap() =~= pt_regs
    && r2.0 == page_ptr
    && r2.1@.is_init()
    && r2.1@.addr() == r2.0
    && r2.1@.value().owning_container == owning_container
    && r2.1@.value().owning_proc == owning_proc
    && r2.1@.value().state == ThreadState::SCHEDULED
    && r2.1@.value().proc_rev_ptr == proc_rev_ptr
    && r2.1@.value().scheduler_rev_ptr == Some(scheduler_rev_ptr)
    && (r2.1@.value().blocking_endpoint_ptr is None)
    && (r2.1@.value().endpoint_rev_ptr is None)
    && (r2.1@.value().running_cpu is None)
    && r2.1@.value().endpoint_descriptors@ =~= Seq::new(
        MAX_NUM_ENDPOINT_DESCRIPTORS as nat,
        |i: int| { None },
    ).update(0, Some(endpoint_ptr))
    && (r2.1@.value().ipc_payload is None)
    && (r2.1@.value().error_code is None)
    && r2.1@.value().trap_frame.unwrap() =~= pt_regs
{
    // Inside this branch every conjunct of BIG_AND holds for both r1 and r2.

    // ret.0 — both pinned to page_ptr.
    assert(r1.0 == page_ptr);
    assert(r2.0 == page_ptr);
    assert(r1.0 == r2.0);

    // is_init / addr equalities.
    assert(r1.1@.is_init());
    assert(r2.1@.is_init());
    assert(r1.1@.is_init() == r2.1@.is_init());
    assert(r1.1@.addr() == r1.0);
    assert(r2.1@.addr() == r2.0);
    assert(r1.1@.addr() == r2.1@.addr());

    // Scalar fields pinned to the same constants ⇒ direct equality.
    assert(r1.1@.value().owning_container == r2.1@.value().owning_container);
    assert(r1.1@.value().owning_proc == r2.1@.value().owning_proc);
    assert(r1.1@.value().proc_rev_ptr == r2.1@.value().proc_rev_ptr);
    assert(r1.1@.value().state == r2.1@.value().state);
    assert(r1.1@.value().scheduler_rev_ptr == r2.1@.value().scheduler_rev_ptr);

    // Option fields pinned to `None` on both runs.
    assert(r1.1@.value().blocking_endpoint_ptr is None);
    assert(r2.1@.value().blocking_endpoint_ptr is None);
    assert(r1.1@.value().blocking_endpoint_ptr == r2.1@.value().blocking_endpoint_ptr);
    assert(r1.1@.value().endpoint_rev_ptr is None);
    assert(r2.1@.value().endpoint_rev_ptr is None);
    assert(r1.1@.value().endpoint_rev_ptr == r2.1@.value().endpoint_rev_ptr);
    assert(r1.1@.value().running_cpu is None);
    assert(r2.1@.value().running_cpu is None);
    assert(r1.1@.value().running_cpu == r2.1@.value().running_cpu);
    assert(r1.1@.value().ipc_payload is None);
    assert(r2.1@.value().ipc_payload is None);
    assert(r1.1@.value().ipc_payload == r2.1@.value().ipc_payload);
    assert(r1.1@.value().error_code is None);
    assert(r2.1@.value().error_code is None);
    assert(r1.1@.value().error_code == r2.1@.value().error_code);

    // endpoint_descriptors: both `@` =~= the same Seq literal, so they =~= each other,
    // and Seq's =~= lifts to == via extensional equality.
    assert(r1.1@.value().endpoint_descriptors@ =~= r2.1@.value().endpoint_descriptors@);
    assert(r1.1@.value().endpoint_descriptors@ == r2.1@.value().endpoint_descriptors@);

    // trap_frame: both `unwrap()`s are =~= pt_regs, so they are =~= each other.
    // (is_Some recommendation comes from `is_init()` + the trap_frame.unwrap() ensures fact.)
    assert(r1.1@.value().trap_frame.unwrap() =~= pt_regs);
    assert(r2.1@.value().trap_frame.unwrap() =~= pt_regs);
    assert(r1.1@.value().trap_frame.unwrap() =~= r2.1@.value().trap_frame.unwrap());
    assert(r1.1@.value().trap_frame.unwrap() == r2.1@.value().trap_frame.unwrap());
}
